-- ============================================================
-- Vetcove YTD Order History Import (2026-01-01 to 2026-07-08)
-- 2977 line items · 4 locations (West Loop, Old Orchard, Lincoln Park, Wheaton)
-- Run in Supabase SQL Editor
-- ============================================================

-- STEP 1: Remove any Vetcove rows accidentally placed in po_items
DELETE FROM po_items
  WHERE auto_flagged = false
  AND week_start >= '2026-01-01'
  AND week_start <= '2026-07-08'
  AND status IN ('received', 'cancelled', 'ordered')
  AND vendor IS NOT NULL;

-- STEP 2: Create dedicated vetcove_orders table
CREATE TABLE IF NOT EXISTS vetcove_orders (
  id           bigserial PRIMARY KEY,
  location_id  uuid,
  product_name text,
  vendor       text,
  sku          text,
  qty_ordered  numeric,
  unit_price   numeric,
  order_date   date,
  status       text,
  created_at   timestamptz DEFAULT now()
);

-- STEP 3: Clear any prior import (idempotent)
DELETE FROM vetcove_orders WHERE order_date >= '2026-01-01' AND order_date <= '2026-07-08';

-- STEP 4: Insert 2977 line items

-- Done: 2977 rows in vetcove_orders
